package kotlinx.coroutines.internal

import kotlinx.coroutines.*
import java.lang.reflect.*
import java.util.*
import java.util.concurrent.locks.*
import kotlin.concurrent.*

private val throwableFields = Throwable::class.java.fieldsCountOrDefault(-1)
private typealias Ctor = (Throwable) -> Throwable?

private val ctorCache = try {
    if (ANDROID_DETECTED) WeakMapCtorCache
    else ClassValueCtorCache
} catch (e: Throwable) {
    // Fallback on Java 6 or exotic setups
    WeakMapCtorCache
}

@Suppress("UNCHECKED_CAST")
internal fun <E : Throwable> tryCopyException(exception: E): E? {
    // Fast path for CopyableThrowable
    if (exception is CopyableThrowable<*>) {
        return runCatching { exception.createCopy() as E? }.getOrNull()
    }
    return ctorCache.get(exception.javaClass).invoke(exception) as E?
}

private fun <E : Throwable> createConstructor(clz: Class<E>): Ctor {
    val nullResult: Ctor = { null } // Pre-cache class
    // Skip reflective copy if an exception has additional fields (that are usually populated in user-defined constructors)
    if (throwableFields != clz.fieldsCountOrDefault(0)) return nullResult
    /*
    * Try to reflectively find constructor(), constructor(message, cause), constructor(cause) or constructor(message).
    * Exceptions are shared among coroutines, so we should copy exception before recovering current stacktrace.
    *
    * Constructors are ranked by priority: (String, Throwable) > (Throwable) > (String) > ()
    * to ensure the best available constructor is always selected regardless of declaration order.
    */
    var bestCtor: Ctor? = null
    var bestPriority = -1
    for (constructor in clz.constructors) {
        val (priority, ctor) = rankConstructor(constructor)
        if (ctor != null && priority > bestPriority) {
            bestCtor = ctor
            bestPriority = priority
            if (bestPriority == 3) break // Already found the best possible constructor
        }
    }
    return bestCtor ?: nullResult
}

/*
 * Returns a pair of (priority, constructor-function) for the given constructor.
 * Priority values: 3 = (String, Throwable), 2 = (Throwable), 1 = (String), 0 = ().
 * Returns (-1, null) if the constructor signature is not recognized.
 */
private fun rankConstructor(constructor: Constructor<*>): Pair<Int, Ctor?> {
    val p = constructor.parameterTypes
    return when (p.size) {
        2 -> when {
            p[0] == String::class.java && p[1] == Throwable::class.java ->
                3 to safeCtor { e -> constructor.newInstance(e.message, e) as Throwable }
            else -> -1 to null
        }
        1 -> when (p[0]) {
            Throwable::class.java ->
                2 to safeCtor { e -> constructor.newInstance(e) as Throwable }
            String::class.java ->
                1 to safeCtor { e -> (constructor.newInstance(e.message) as Throwable).also { it.initCause(e) } }
            else -> -1 to null
        }
        0 -> 0 to safeCtor { e -> (constructor.newInstance() as Throwable).also { it.initCause(e) } }
        else -> -1 to null
    }
